def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.25
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-(ratio * 12)) + 0.12
        elif 0.3 < ratio <= 0.7:
            temp_score = 0
            for k in range(1, 8):
                sign = (-1) ** (k + 1)
                temp_score += sign * (ratio ** (k + 2)) / (k + 1)
            score = abs(temp_score) + 0.07
        else:
            score = 1 / (ratio + 0.2) + 0.15
        neighbors_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    if diff_ratio > 0.6:
                        weight = 1 / (offset * 1.2)
                    else:
                        weight = 1 / offset
                    neighbors_influence += diff_ratio * weight * 0.1
        capacity_factor = np.sqrt(capacity)
        if capacity_factor < 1e-3:
            capacity_factor = 1
        penalty = 0
        if ratio < 0.4:
            penalty = (0.4 - ratio) ** 2 * 0.5
        elif ratio > 0.85:
            penalty = (ratio - 0.85) ** 3 * 0.3
        priority = score + neighbors_influence / capacity_factor + penalty
        if priority < 0:
            priority = 0
        pattern_score = 0.0
        for step in range(1,4):
            left_idx = i - step
            right_idx = i + step
            left_cap = bins[left_idx] if left_idx >=0 else None
            right_cap = bins[right_idx] if right_idx < n else None
            if left_cap is not None and right_cap is not None and left_cap > 0 and right_cap >0:
                if abs(left_cap - right_cap) < capacity * 0.2:
                    pattern_score += 0.02 * step
            elif left_cap is not None and left_cap > 0:
                pattern_score += 0.01 * step
            elif right_cap is not None and right_cap > 0:
                pattern_score += 0.01 * step
        priority -= pattern_score
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 10
    return priorities
